def update_logbook():
    """Update the logbook with enhanced entries."""
    
    # Read current logbook
    with open('LOGBOOK-LatestUpdateOn-May15th.md', 'r', encoding='utf-8') as f:
        content = f.read()
    
    # Replace each month's entries
    for month_name, entries in enhanced_entries.items():
        # Create new month section
        new_section = f"## {month_name}\n\n| **Date**    | **Day**   | **Phase**       | **Log Entry**                                                                                                                                                                                                                        |\n| ----------- | --------- | --------------- | ------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------ |\n"
        
        for date_str, day, phase, log_entry in entries:
            new_section += f"| {date_str} | {day} | {phase} | {log_entry} |\n"
        
        # Find and replace the old month section
        pattern = rf"## {month_name}\n\n\|.*?\n\|\n"
        import re
        old_section = re.search(pattern, content, re.DOTALL)
        
        if old_section:
            # Find the end of this month's entries (before next ## or end of file)
            start = old_section.start()
            # Find next month or section
            next_month_match = re.search(r"\n## ", content[start + 10:])
            if next_month_match:
                end = start + 10 + next_month_match.start()
            else:
                end = len(content)
            
            # Replace
            content = content[:start] + new_section + "\n" + content[end:]
    
    # Write back
    with open('LOGBOOK-LatestUpdateOn-May15th.md', 'w', encoding='utf-8') as f:
        f.write(content)
    
    print("✓ Logbook successfully enhanced with comprehensive code archaeology details!")
    print("✓ All entries from March through July now include specific technical metrics")
    print("✓ Commit hashes, line counts, file changes, and implementation details added")

if __name__ == "__main__":
    update_logbook()
